var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"이런 건…… 이런 건 처음 봐.","JPN":"こんな……こんなの初めて。","ENG":"Oh my... I've never seen anything like it.","TWN":"這……這我還是第一次看到！"},"stage":{"bg":"HAVEN","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"유연하면서도 절도 있고 거칠면서도 우아해!","JPN":"しなやかでありがら節度があって、荒いながらも優雅！","ENG":"It's gracious, but rough! Flexible, yet so disciplined!","TWN":"柔軟卻不失節奏，既粗暴又優雅！"},"stage":{"bg":"HAVEN","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"꼭 심해에 사는 해파리처럼!","JPN":"まるで深海に住んでるクラゲのように！","ENG":"It's like... watching a jellyfish swim!","TWN":"彷彿是深海裡的水母那般！"},"stage":{"bg":"HAVEN","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"MAYA_FRONTIER_NULL_NULL","text":{"KOREA":"맞아! 보미 언니의 움직임에 루미 언니의 폭발력이 더해진 것 같았어!","JPN":"そうです！　ボミの動きにルミの爆発力が加わった感じなのです！","ENG":"You're right! It's like watching Bomi's movements and Lumi's explosiveness all in one!","TWN":"沒錯！感覺就像是普美姊姊的動作，再加上魯米姊姊的爆發力！"},"stage":{"bg":"HAVEN","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"후후, 드디어 이 토미님의 자리를 물려 받을 천재 댄서가 탄생했군.","JPN":"ふふ、やっとこのトミー様の跡を継ぐ天才ダンサーが誕生したな。","ENG":"Hah hah! I think I've finally found a dance genius to succeed me on my throne.","TWN":"呵呵，湯米我終於後繼有人啦，新一代的天才舞者誕生！"},"stage":{"bg":"HAVEN","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"멀리서나마… 보고 있나? 제리, 미키.","JPN":"遠くから……見てるか？　ジェリー、ミッキー。","ENG":"Are you watching from afar too... Jerry, Mickey?","TWN":"你們…也在遠方看著嗎？傑瑞、米奇。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"지금 여기서 전설이 탄생하고…….","JPN":"今ここで伝説が誕生して……","ENG":"We are witnessing the birth of a legend–","TWN":"這個傳奇誕生的瞬間……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"우리 멀쩡하게 살아 있어, 이 자식아!","JPN":"俺らを勝手に死んでることにするな、この野郎！","ENG":"HEY! We're still alive, ya dimwit!","TWN":"你這臭小子，我們還健在好嗎！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"핫도그 사 오겠다더니 여기서 뭘 하고 있는 거야, 대체?","JPN":"ホットドック買いに行ったやつがこんなところで何してんだよ？　まったく！","ENG":"You said you were getting a hotdog! What are you even doing here?!","TWN":"你不是去買熱狗嗎？到底在這幹嘛？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DEALER_NPC_HAVEN_NULL","text":{"KOREA":"심사 결과 전달받았습니다. 이번 대결 우승자는……","JPN":"審査の結果を教えていただきました。この対決の勝者は……","ENG":"The results are in. The winner of this round is...","TWN":"評審結果出爐，這次獲勝的是……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEALER_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DEALER_NPC_HAVEN_NULL","text":{"KOREA":"축하합니다! 토토 님의 승리입니다!","JPN":"おめでとうございます！　トト様の勝利です！","ENG":"Congratulations! Mr. Toto is the winner!","TWN":"恭喜！由托托勝出！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEALER_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L21_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"해……! 해냈어, 토토!","JPN":"や……！　やったよ、トト！","ENG":"Y-you did it! We did it, Toto!","TWN":"成……！成功了，托托！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……그냥 뭐든 잡아먹겠다고 날뛰던 거 아냐? 진짜 이겼다고?","JPN":"……全部食ってやるって暴れてたんじゃないの？　マジで勝っちゃった？","ENG":"...Wasn't that him just flapping around trying to eat everything? How did he even win?","TWN":"……它不就一副什麼都想吃的樣子嗎？這樣就贏啦？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"리온! 토토! 정말 잘했어!!","JPN":"リオン！　トト！　本当によくやった！","ENG":"Liona! Toto! You did great!","TWN":"萊恩！托托！幹得好！！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"대단한데? 그런 무빙은 이제껏 없던 데이터야. 보는 내내 가슴이 조마조마하더라.","JPN":"すごいね。あのムービング、今まで見たことのないデータだよ。見てる間ハラハラしどおしだった。","ENG":"That was amazing. It was unlike any movement data I've ever observed before. It had me on my toes the whole time.","TWN":"好厲害！我的資料庫裡也沒有那樣的律動，看著看著我的心也跟著跳得很快呢！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"나도 배울래, 토토! 나도 알려 줘! 응?","JPN":"私にも踊り教えて、トト！　私にも！　ね？","ENG":"Toto! Teach me too! Pleaaase? Hmm?","TWN":"我也要學！托托教我！拜託？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"애완 동물을 도전자로 내세우다니, 이거 한 방 먹었군.","JPN":"ペットを挑戦者として出場させるとは、こりゃ一発食らったな。","ENG":"Putting a pet up as the challenger. I didn't expect that.","TWN":"竟然推派寵物當挑戰者，被擺了一道呢。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"패배를 인정하지. 멋진 승부였다.","JPN":"負けを認めよう。いい勝負だった。","ENG":"I admit my defeat. Good show.","TWN":"我認輸，是場精彩的對決。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아니, 그걸 그냥 인정하면 안 되죠!","JPN":"いや、そのまま認めちゃっていいの！？","ENG":"Wait, you're seriously going to admit that?","TWN":"等等，怎麼可以這樣就認輸！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"맞아. 인정할 수 없어. 토토는 애완 동물이 아니라 내 친구니까.","JPN":"そうだよ。認められない。トトはペットじゃなくて友達なんだから。","ENG":"She's right. Toto's not my pet. He's my friend.","TWN":"對啊，我不同意，托托是我的朋友，才不是什麼寵物！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"하하핫! 이거 내가 큰 실례를 저질렀군!","JPN":"はははっ！　これはこれは、大変失礼した！","ENG":"Hahaha! Please excuse my rudeness.","TWN":"哈哈哈！我真是太失禮了！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"받아라. 이건 승리한 도전자에게 주는 VIP 카드야.","JPN":"ほらよ。これが勝利した挑戦者に与えられるVIPカードだ。","ENG":"Here you go. This is the VIP card given to the challenge winners.","TWN":"拿去吧，這是獲勝的挑戰者可以獲得的VIP卡。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"진짜야? 이렇게 쉽게 넘겨 줘도 돼?","JPN":"マジで？　こんなに簡単にもらってもいいの？","ENG":"Really? You're just gonna give it to us?","TWN":"真的嗎？這麼輕易就給我們？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"속임수를 썼다고 모함하거나, 숨겨진 조건이 있다거나. 종목을 바꾼다거나.","JPN":"イカサマをして陥れるとか、隠された条件があるとか。種目を変えるとか、ない？","ENG":"You're not going to accuse us of cheating, claim there's a hidden condition, or attempt to change the game for a rematch?","TWN":"該不會是想誣賴我們耍詐，還是有什麼隱藏條件，或是想搞什麼名堂？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"그런 식으로 비겁하게 이겨서 뭐가 재밌지?","JPN":"そんな卑怯な方法で勝って何が面白いんだ？","ENG":"What's the fun in winning if it's not fair?","TWN":"用這種小人的招數比贏又有什麼意思？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"안심해라. 너희들의 노력과 열정은 여기 모인 모두가 지켜봤어.","JPN":"安心しろ。ここに集まったみんながお前たちの努力と情熱の証人だ。","ENG":"Don't worry. Everyone here has witnessed your effort and passion.","TWN":"安啦，在場的大家都有看到你們的努力和熱情。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤이븐 랜드…… 정말 이래도 되는 거 맞아?","JPN":"ヘイブンランド……本当にこれでいいの？","ENG":"Is it really okay for Havenland... to do this?","TWN":"天堂樂園……這樣搞真的沒問題嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"누구 손목 하나 날아가도 이상하지 않을 험악하고 무서운 분위기여야 하는 거 아니냐고.","JPN":"誰かの手首が飛んじゃってもおかしくない、険悪で怖い雰囲気のはずなのに。","ENG":"Isn't this supposed to be a scary place where someone getting their arm cut off at the wrist is the norm?","TWN":"不是應該充滿殺戮之氣，就算斷隻手或斷隻腿也不覺得奇怪才對嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"잠깐, 너 아까부터 계속 이상한 말을 하는데……","JPN":"ちょっと、君さっきから変なことばっかり言ってるけど……","ENG":"Whoa, why do you keep saying weird stuff like that?","TWN":"等等，你從剛才就一直說些奇怪的話……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"이게 바로 헤이븐 랜드야. 모두 재밌게 게임을 하고, 승자와 패자 모두 즐길 수 있는 곳!","JPN":"これこそがヘイブンランドなんだ。みんな楽しくゲームをして、勝者も敗者も楽しめる場所！","ENG":"This is what Havenland is all about. Having fun playing games, no matter the outcome!","TWN":"這就是天堂樂園，大家一起開心玩遊戲，不論贏家或輸家都歡喜的地方！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아니. 직접 보고도 안 믿긴다니까. 내가 알던 상식이 파괴되는 기분이라고.","JPN":"いや。直接見ても信じられないんだって。私の中の常識が破壊される気分だよ。","ENG":"I mean, I still can't believe what I'm seeing here. It's like my whole life's been a lie.","TWN":"才不是，就算我親眼見到也無法置信，這根本刷新我的三觀！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"뭐, 실제로 그런 일들도 빈번하지.","JPN":"ま、実際にそういうこともよく発生する。","ENG":"Well, stuff like that does happen here sometimes.","TWN":"你說的那些確實是常有的事。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"……어?","JPN":"……え？","ENG":"...Huh?","TWN":"……什麼？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"평의회에 들어간 뒤부터였을 거야. 질 나쁜 놈들이 부쩍 늘어났던 건.","JPN":"評議会に加入してからだろうな。質の悪いやつらがぐっと増えたのは。","ENG":"After we joined the Council, the number of bad apples skyrocketed.","TWN":"自從加入評議會後，惡劣的傢伙突然暴增。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"그런 놈들을 조용히 솎아내서 분리해 두는 것도 형님을 따르는 우리들 일이다.","JPN":"そういうやつらを静かに捕まえて分離しておくのも、兄貴についてる俺たちの仕事だ。","ENG":"It is our responsibility as Mr. Haven's consiglieres to weed them out and keep them in check.","TWN":"而我們這群跟隨大哥的人，主要的工作就是剷除那些傢伙。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"역시! 눈에 띄지 않게 헤이븐 형님을 보좌하시는 거였군요!","JPN":"さすが！　見えないところでヘイブン兄貴を補佐してるんですね！","ENG":"I knew it! You've all been quietly assisting Mr. Haven!","TWN":"我就知道！你默默地在輔佐天堂大哥對吧！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"그럴 리가…… 난 그런 얘기 한 번도 못 들어 봤는데?","JPN":"そんな……僕にそんな話は一度も入ってきてないけど。","ENG":"No way... I never heard anything about this...","TWN":"怎麼可能……這些事我怎麼從來沒聽說過？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"관심을 갖지 않으면 보일 것도 보이지 않아. 형님을 만나기 전의 나도 그랬지.","JPN":"興味を持たないと見えるものも見えなくなる。兄貴に出会う前の俺もそうだった。","ENG":"You won't see it unless you pay attention to it. I was much like you before I met him.","TWN":"人對於不關心的事都是選擇視而不見的，在遇見大哥之前我也是這樣。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"뭐, 어떤 놈들이 와도 라스트 헤이븐은 앞으로도 계속 청정 구역으로 남을 거다.","JPN":"まあ、どんなやつらが来てもラストヘイブンはこれからもずっと綺麗な区域のままだ。","ENG":"Well, no matter who steps in here, Last Haven will continue to be a clean and friendly place.","TWN":"總之，不管來的是什麼樣的傢伙，最後的天堂一直都會是片淨土。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"누가 뭐래도 헤이븐 형님이 일어선 기반 같은 곳이니까.","JPN":"誰が何と言おうとも、ヘイブン兄貴が立ち上がった基盤のようなところだからな。","ENG":"No matter what they say, this is the foundation where Mr. Haven began his story.","TWN":"不管誰怎麼說，這裡畢竟是天堂大哥的起點。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"이 길을 쭉 따라가면 드림 네버 랜드가 나온다.","JPN":"この道をまっすぐ行くとドリームネバーランドに着く。","ENG":"If you follow this path, it'll lead you to Dream Neverland.","TWN":"沿著這條路一直走就會看到夢幻樂園。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"다음 도전도 쉽진 않을 거야. 행운을 빌어 주지.","JPN":"次の挑戦も一筋縄じゃいかないぞ。うまくいくといいな。","ENG":"The next challenge will be harder than this one. I wish you luck.","TWN":"下一個挑戰也不容易，祝你們好運。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그래도 돼, 아저씨? 이러다 우리가 정말로 헤이븐 랜드를 차지하면 어쩌려고?","JPN":"いいの？　おじさん。私たちが本当にヘイブンランドを手に入れるかもしれないよ？","ENG":"Hey mister, you sure about this? I mean, what if we really do become the new owners of Havenland?","TWN":"大叔，這樣真的沒關係嗎？萬一我們真的拿下天堂樂園怎麼辦？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"하핫. 헤이븐 랜드에 새바람을 불러온다면 그것도 나쁘지 않은 결과겠지.","JPN":"ははっ。ヘイブンランドに新しい風が吹くなら、それも悪くない。","ENG":"Haha! I wouldn't mind a breath of fresh air here at Havenland.","TWN":"哈哈，要是天堂樂園可以迎來新氣象，那也是不錯的結果吧？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"하지만 말처럼 쉽지는 않을 거야.","JPN":"だが、言うほど簡単にはいかないだろうな。","ENG":"But like I said, it won't be easy.","TWN":"不過就如同我剛說的，事情沒這麼容易的。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"내가 헤이븐 형님의 말을 믿게 된 건……. 형님의 힘을 내 눈으로 봤기 때문이니까.","JPN":"俺がヘイブン兄貴の言葉を信じるようになったのは……兄貴の力をこの目で見たからだ。","ENG":"The only reason why I believe in Mr. Haven... is because I saw his strength with my own eyes.","TWN":"我之所以會相信天堂大哥的話……是因為我親眼見過大哥的能力。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"힘?","JPN":"力？","ENG":"His strength?","TWN":"能力？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"3종 침식체.","JPN":"第3種侵食体。","ENG":"A Category 3 C.O.","TWN":"3類侵蝕體。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"그래. 내 동료들을 몰살시켰던 그 괴물을, 형님은 그 주먹 한 방으로 박살내 버리셨지.","JPN":"そう。俺の仲間たちを全滅させたあの化け物を、兄貴は拳一発でやっつけたんだ。","ENG":"Yeah, the same monster that annihilated my buddies. He obliterated it with one punch.","TWN":"沒錯，大哥只用一拳，便將那些殺害夥伴的怪物粉碎。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"3종 침식체를…… 일격에?","JPN":"第3種侵食体を……一撃で？","ENG":"He killed a Category 3 C.O... in one blow?!","TWN":"一拳……擊倒3類侵蝕體？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그게 사람이 가능한 일이야?","JPN":"それ、人間にできることなの？","ENG":"Is that even humanly possible?","TWN":"人類有可能辦到嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"아니……. 과장이야. 절대 과장이라고.","JPN":"いや……大げさだよ。絶対違う。","ENG":"No... It's an exaggeration. It's definitely an exaggeration.","TWN":"沒有啦……是誇飾法，絕對是誇飾法。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"뭐야, 너희들. 하나도 모르고 있었구나?","JPN":"何だよ、アンタたち。何も知らないんだね？","ENG":"Wow, you guys. You really don't know anything, do you?","TWN":"搞什麼，你們根本什麼都不知道嘛！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"오오, 그럼 그 헤이븐이란 사람이랑은 무슨 놀이를 하는 거야?","JPN":"おお、じゃあそのヘイブンって人とは何して遊ぶの？","ENG":"Ooh... Then what kind of game are we playing with this Haven person?","TWN":"哇喔，那我們要和那個叫天堂的人玩什麼呢？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Uh...","TWN":"呃……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"싸, 싸워야 하겠지. 헤이븐 형님 담당은 투기장이니까.","JPN":"た、戦うんだろね。ヘイブン兄貴の担当は闘技場だから。","ENG":"W-we fight, I guess? He's in charge of the colosseum.","TWN":"當…當然是要打一場囉，天堂大哥負責的是競技場。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"하하핫. 그렇다고 벌써부터 겁 먹을 필요 없어.","JPN":"はははっ。だからといって、今から怯える必要はないぞ。","ENG":"Hahaha! There's no need to be afraid right now.","TWN":"哈哈哈，也不需要現在就開始害怕啦。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"재치를 발휘해. 이번처럼. 그렇다면 방법을 찾을 수 있을지도 몰라.","JPN":"さっきのように気転を利かせるんだ。そうすれば方法も見つかるだろう。","ENG":"Use your wits, just like you did this time. I'm sure you'll find a way.","TWN":"發揮你們的才能，或許就能像這次一樣找到方法囉！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"어쩐지…… 저희가 이기길 바라는 것 같아요.","JPN":"なんか……私たちに勝ってほしいみたいですね。","ENG":"It's almost as if... you want us to win.","TWN":"怎麼覺得……大叔好像希望我們贏的樣子。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"아무래도 간부다 보니 여기저기 들려오는 소문들이 많은 법이거든.","JPN":"幹部なんかやってると、あちこちから流れてくる噂が否応なしに耳に入る。","ENG":"Being a consigliere, you hear a lot of rumors.","TWN":"身為幹部，常常會聽到一些流言，"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"최근 헤이븐 형님은 고민이 많으신 듯했어. 그럴 때는 분위기 전환이 필요한 법이지.","JPN":"最近ヘイブン兄貴はとても悩んでる様子だった。そういう時には雰囲気を変える必要があるからな。","ENG":"It seemed like Mr. Haven had a lot of worries recently. It's in times like this when you need change.","TWN":"最近天堂大哥似乎有許多煩惱，這種時候就需要轉換一下氛圍。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"기회가 되면 또 한 번 붙어보자! 나도 다음에는 더 멋진 춤을 준비할 테니까!","JPN":"機会があったらまた勝負しよう！　俺も次はもっとかっこいいダンスを用意しておく！","ENG":"Let's battle once more if we get the chance! I'll be practicing my moves until then!","TWN":"希望有機會可以再交手！下次我會準備更厲害的舞！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"}]`);export{e as default};